using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private LiveStudioClient _client;
        private DateTime _lastSpawnTime = DateTime.MinValue;
        private static readonly Random _random = new Random();
        private static readonly VehicleHash[] _sportsCars = new VehicleHash[]
        {
            VehicleHash.Cheetah,
            VehicleHash.Infernus,
            VehicleHash.Vacca,
            VehicleHash.TurismoR,
            VehicleHash.Jester,
            VehicleHash.Massacro,
            VehicleHash.Feltzer,
            VehicleHash.Schafter2,
            VehicleHash.Surano
        };

        // Track spawned vehicles for potential future cleanup
        private List<Vehicle> _spawnedVehicles = new List<Vehicle>();

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() =>
                    GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();
        }

        private void OnAborted(object sender, EventArgs e)
        {
            _client?.Dispose();
        }

        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is GiftEvent gift)
            {
                if (gift.GiftId == "rose")
                    TrySpawnCar();
            }
            else if (evt is ChatEvent chat)
            {
                if (chat.Content.Trim().Equals("!rose", StringComparison.OrdinalIgnoreCase))
                    TrySpawnCar();
            }
        }

        private void TrySpawnCar()
        {
            MainThreadDispatcher.Enqueue(() =>
            {
                var now = DateTime.UtcNow;
                if ((now - _lastSpawnTime).TotalSeconds < 60)
                {
                    int remaining = 60 - (int)(now - _lastSpawnTime).TotalSeconds;
                    GTA.UI.Notification.Show("~y~Cooldown active. ~w~Please wait " + remaining + "s.");
                    return;
                }

                _lastSpawnTime = now;

                Ped playerPed = Game.Player.Character;
                Vector3 forward = playerPed.ForwardVector;
                Vector3 spawnPos = playerPed.Position + forward * 5.0f;

                Vector3 checkPos = spawnPos + new Vector3(0, 0, 100.0f);
                RaycastResult ray = World.Raycast(checkPos, Vector3.WorldDown, 200.0f,
                    IntersectFlags.Everything, null);
                if (ray.DidHit)
                    spawnPos = ray.HitPosition;
                else
                    spawnPos = World.GetNextPositionOnStreet(spawnPos);

                VehicleHash selected = _sportsCars[_random.Next(_sportsCars.Length)];
                Vehicle veh = World.CreateVehicle(selected, spawnPos, playerPed.Heading);
                _spawnedVehicles.Add(veh);

                GTA.UI.Notification.Show("~g~A viewer sent a rose! ~w~Sports car delivered.");
            });
        }
    }
}
